SELECT COUNT(*) AS quantidade FROM servidor s WHERE LOWER(s.contrato) = LOWER('efetivos') AND LOWER(s.area_ingresso) = LOWER('geociencias') AND LOWER(s.sigla_campus) = LOWER('jat') AND s.pk_siape IN (SELECT chm.siape FROM calc_hora_aula_media chm WHERE chm.ano = 2020 AND chm.semestre = 1 AND LOWER(chm.area_ingresso) = LOWER('geociencias') AND LOWER(chm.sigla_campus) = LOWER('jat'))